const PSYCHE_GRIND_LEAN_SOURCE =
  'open-source/gnosis/lean/Lean/ForkRaceFoldTheorems/PsycheGrind.lean';

const PSYCHE_GRIND_EXTENDED_LEAN_SOURCE =
  'open-source/gnosis/lean/Lean/ForkRaceFoldTheorems/PsycheGrindExtended.lean';

type TwinPsycheTheoremTrace = Pick<
  TwinPsycheTheoremDefinition,
  'leanName' | 'leanSourcePath'
>;

function toTheoremId(
  leanName: string,
  polarity: TwinPsycheTheoremPolarity = 'theorem'
): string {
  const prefix = polarity === 'theorem' ? 'THM-' : 'ANTI-THM-';
  return `${prefix}${leanName.replaceAll('_', '-').toUpperCase()}`;
}

function theorem(
  passId: TwinPsycheTheoremPassId,
  id: string,
  title: string,
  insight: string,
  trace?: TwinPsycheTheoremTrace
): TwinPsycheTheoremDefinition {
  return { id, passId, polarity: 'theorem', title, insight, ...trace };
}

function antitheorem(
  passId: TwinPsycheTheoremPassId,
  id: string,
  title: string,
  insight: string,
  trace?: TwinPsycheTheoremTrace
): TwinPsycheTheoremDefinition {
  return { id, passId, polarity: 'antitheorem', title, insight, ...trace };
}

function leanTheorem(
  passId: TwinPsycheTheoremPassId,
  leanName: string,
  title: string,
  insight: string,
  leanSourcePath = PSYCHE_GRIND_LEAN_SOURCE
): TwinPsycheTheoremDefinition {
  return theorem(passId, toTheoremId(leanName), title, insight, {
    leanName,
    leanSourcePath,
  });
}

