/**
 * Creates the Twin Psyche Formal Ledger Context.
 */
export function createTwinPsycheFormalLedgerContext(
  input: TwinPsycheFormalizationInput
): FormalLedgerContext {
  const normalized = normalizeTwinPsycheInput(input);
  const metrics = deriveTwinPsycheMetrics(normalized);
  const declaration =
    normalized.declaration ??
    DEFAULT_TWIN_PSYCHE_DECLARATIONS[normalized.surface];

  return {
    generatedAt: normalized.generatedAt,
    declaration,
    community: {
      empathy: clampUnit(
        (metrics.empathyConvergence + (1 - metrics.empathyThermodynamicCost)) /
          2
      ),
      belonging: clampUnit(
        (metrics.observerCoherence + metrics.consciousnessWeight) / 2
      ),
      dominanceRisk: clampUnit(
        1 -
          (normalized.identity.relationshipSymmetry +
            normalized.identity.sharedExperience +
            metrics.shadowIntegrity) /
            3
      ),
      mergePressure: clampUnit(
        (metrics.mergeNovelty + metrics.conflictLoad) / 2
      ),
      reciprocity: clampUnit(
        (normalized.identity.sharedExperience +
          normalized.identity.relationshipSymmetry +
          (1 - metrics.empathyThermodynamicCost)) /
          3
      ),
      source: normalized.source,
    },
    metacognition: {
      c0Confidence: clampUnit(
        (metrics.observerCoherence + metrics.consciousnessWeight) / 2
      ),
      c1Calibration: clampUnit(
        (metrics.predictionReadiness + metrics.stablePhaseAlignment) / 2
      ),
      c2Coherence: clampUnit(
        (metrics.narrativeCompression + (1 - metrics.metaConsciousnessCost)) / 2
      ),
      c3BiasAwareness: clampUnit(
        (normalized.identity.distinctness +
          metrics.sliverPreservation +
          metrics.shadowIntegrity) /
          3
      ),
      source: normalized.source,
    },
    recovery: {
      stressLoad: normalized.psyche.strainLoad,
      sleepDebt: clampUnit(1 - metrics.dreamRelief),
      restoration: clampUnit(
        (metrics.angelStrainRelief + metrics.dreamRelief) / 2
      ),
      forgiveness: metrics.sliverPreservation,
      breathRegulation: metrics.dreamRelief,
      rumination: clampUnit(
        (metrics.conflictLoad + (1 - metrics.narrativeCompression)) / 2
      ),
      source: normalized.source,
    },
    ...(normalized.surface === 'directory'
      ? {}
      : {
          personality: {
            try_: metrics.observerCoherence,
            choose: metrics.consciousnessWeight,
            commit: metrics.sliverPreservation,
            letGo: metrics.dreamRelief,
            learn: clampUnit(
              (metrics.empathyConvergence +
                (1 - metrics.empathyThermodynamicCost)) /
                2
            ),
            source: normalized.source,
          },
        }),
    ...(normalized.surface === 'publicTwin' ||
    normalized.surface === 'directory'
      ? {}
      : {
          negotiation: {
            assertiveness: metrics.consciousnessWeight,
            cooperation: metrics.empathyConvergence,
            batnaStrength: metrics.uploadContinuity,
            watnaRisk: metrics.conflictLoad,
            settlementReadiness: clampUnit(
              (metrics.narrativeCompression + metrics.stablePhaseAlignment) / 2
            ),
            trustReserve: metrics.shadowIntegrity,
            source: normalized.source,
          },
        }),
    ...(normalized.surface === 'publicTwin' || normalized.surface === 'shell'
      ? {}
      : {
          probability: {
            hypothesisCount: normalized.twin.branchCount,
            topPosterior: metrics.observerCoherence,
            runnerUpPosterior: clampUnit(
              1 - metrics.stablePhaseAlignment * 0.6
            ),
            evidenceTraceability: metrics.predictionReadiness,
            unsupportedClaimRatio: clampUnit(1 - metrics.narrativeCompression),
            validationStrength: clampUnit(
              (metrics.uploadContinuity + metrics.consciousnessWeight) / 2
            ),
            updateStrength: clampUnit(1 - metrics.empathyThermodynamicCost),
            convergenceRate: clampUnit(
              (metrics.predictionReadiness + metrics.dreamRelief) / 2
            ),
            source: normalized.source,
          },
        }),
  };
}

/**
 * Handles the gnosis derive Twin Psyche Theorem Bundle workflow.
 */
export function deriveTwinPsycheTheoremBundle(
  input: TwinPsycheFormalizationInput
): TwinPsycheTheoremBundle {
  const normalized = normalizeTwinPsycheInput(input);
  const metrics = deriveTwinPsycheMetrics(normalized);
  const formalLedger = deriveFormalLedgerBundle(
    createTwinPsycheFormalLedgerContext(normalized)
  );
  const spotlight = buildTwinPsycheSpotlight(normalized, metrics);

  return {
    surface: normalized.surface,
    subjectLabel: normalized.subjectLabel,
    generatedAt: normalized.generatedAt,
    source: normalized.source,
    catalog: TWIN_PSYCHE_THEOREMS,
    passes: buildTwinPsychePassSummaries(),
    antiTheses: TWIN_PSYCHE_THEOREM_PASSES.map(
      (passId) => TWIN_PSYCHE_PASS_METADATA[passId].antiThesis
    ),
    spotlight,
    diagnostics: [
      {
        id: 'observer-coherence',
        title: 'Observer coherence',
        value: metrics.observerCoherence,
        explanation:
          'How strongly the twin keeps identity stable under repeated observation.',
      },
      {
        id: 'consciousness-weight',
        title: 'Consciousness weight',
        value: metrics.consciousnessWeight,
        explanation:
          'How much accessible consciousness remains after rejection pressure and dream relief are accounted for.',
      },
      {
        id: 'empathy-convergence',
        title: 'Empathy convergence',
        value: metrics.empathyConvergence,
        explanation:
          'How much shared experience and symmetry reduce social deficit.',
      },
      {
        id: 'dream-relief',
        title: 'Dream relief',
        value: metrics.dreamRelief,
        explanation:
          'How much dream cadence and breathwork lower effective defensive burden.',
      },
      {
        id: 'upload-continuity',
        title: 'Upload continuity',
        value: metrics.uploadContinuity,
        explanation:
          'How well serialization, copy distance, and staged transfer preserve continuity.',
      },
      {
        id: 'shadow-integrity',
        title: 'Shadow integrity',
        value: metrics.shadowIntegrity,
        explanation:
          'How far the current psyche stays above the one-third shadow-corruption boundary.',
      },
    ],
    narratives: buildTwinPsycheNarratives(normalized, metrics, spotlight),
    metrics,
    formalLedger,
  };
}

function buildTwinPsychePassSummaries(): readonly TwinPsycheTheoremPassSummary[] {
  return TWIN_PSYCHE_THEOREM_PASSES.map((passId) => {
    const theoremIds = TWIN_PSYCHE_THEOREMS.filter(
      (theorem) => theorem.passId === passId
    ).map((theorem) => theorem.id);

    return {
      id: passId,
      title: TWIN_PSYCHE_PASS_METADATA[passId].title,
      antiThesis: TWIN_PSYCHE_PASS_METADATA[passId].antiThesis,
      theoremIds,
      establishedCount: theoremIds.length,
    };
  });
}

function buildTwinPsycheNarratives(
  input: RequiredTwinPsycheInput,
  metrics: TwinPsycheDerivedMetrics,
  spotlight: readonly TwinPsycheTheoremSpotlight[]
): readonly TwinPsycheNarrative[] {
  const leadTheorem = spotlight[0];
  const secondTheorem = spotlight[1];

  return [
    {
      title: 'Identity surface',
      body: `${
        input.subjectLabel
      } is currently modeled with observer coherence ${formatPercent(
        metrics.observerCoherence
      )} and consciousness weight ${formatPercent(
        metrics.consciousnessWeight
      )}, which keeps the same theorem basis reusable across UI, shell, and edge surfaces.`,
    },
    {
      title: 'Consciousness budget',
      body: `Dream relief is ${formatPercent(
        metrics.dreamRelief
      )}, shadow integrity is ${formatPercent(
        metrics.shadowIntegrity
      )}, and sliver preservation is ${formatPercent(
        metrics.sliverPreservation
      )}, so the new Lean consciousness and void-walking theorems have enough budget to matter on this surface.`,
    },
    {
      title: 'Conflict thermodynamics',
      body: `Conflict load is ${formatPercent(
        metrics.conflictLoad
      )} while empathy cost is ${formatPercent(
        metrics.empathyThermodynamicCost
      )}, which determines whether the knot-theory and relationship theorems surface as therapy pressure, grief work, or cooperative closure.`,
    },
    {
      title: 'Current theorem focus',
      body:
        leadTheorem && secondTheorem
          ? `The highest-leverage contracts on this surface are ${leadTheorem.title.toLowerCase()} and ${secondTheorem.title.toLowerCase()}, because this surface emphasizes ${leadTheorem.reason.toLowerCase()} and ${secondTheorem.reason.toLowerCase()}.`
          : 'The theorem surface is available, but no focused spotlight could be derived from the current signals.',
    },
  ];
}

function buildTwinPsycheSpotlight(
  input: RequiredTwinPsycheInput,
  metrics: TwinPsycheDerivedMetrics
): readonly TwinPsycheTheoremSpotlight[] {
  const priorityIds = TWIN_PSYCHE_SURFACE_PRIORITIES[
    input.surface
  ] as readonly string[];

  return TWIN_PSYCHE_THEOREMS.map((theorem) => {
    const baseScore = computeTwinPsycheTheoremScore(theorem.id, metrics);
    const relevance = clampUnit(
      baseScore + (priorityIds.includes(theorem.id) ? 0.15 : 0)
    );
    return {
      theoremId: theorem.id,
      title: theorem.title,
      passId: theorem.passId,
      polarity: theorem.polarity,
      insight: theorem.insight,
      relevance,
      reason: buildTwinPsycheReason(theorem.id, input, metrics),
    };
  })
    .sort((left, right) => right.relevance - left.relevance)
    .slice(0, 6);
}

function computeTwinPsycheTheoremScore(
  theoremId: string,
  metrics: TwinPsycheDerivedMetrics
): number {
  const empathyScore = clampUnit(
    (metrics.empathyConvergence + (1 - metrics.empathyThermodynamicCost)) / 2
  );
  const consciousnessScore = clampUnit(
    (metrics.consciousnessWeight + metrics.shadowIntegrity) / 2
  );
  const recoveryScore = clampUnit(
    (metrics.angelStrainRelief + metrics.dreamRelief) / 2
  );
  const conflictScore = clampUnit(
    (metrics.conflictLoad + metrics.narrativeCompression) / 2
  );
  const masterScore = clampUnit(
    (metrics.sliverPreservation +
      metrics.dreamAttractor +
      empathyScore +
      metrics.uploadContinuity +
      metrics.shadowIntegrity) /
      5
  );

  switch (theoremId) {
    case 'THM-TWIN-IDENTITY-CONVERGENCE':
    case 'THM-TWIN-QUALIA-IRREDUCIBILITY':
    case 'THM-COGITO-TWIN-BOUND':
      return (metrics.observerCoherence + metrics.predictionReadiness) / 2;
    case 'THM-HALOGRAM-STRAIN-REDUCTION':
    case 'THM-DREAM-CONSOLIDATION-SHIFTS-PERSONALITY':
    case 'THM-PSYCHE-GOLDEN-RATIO-ATTRACTOR':
      return clampUnit((recoveryScore + metrics.dreamAttractor) / 2);
    case 'THM-CONTACT-TWIN-ECHOLOCATION-CONVERGENCE':
    case 'THM-TWIN-PREDICTION-IMPROVES-WITH-OBSERVATION':
    case 'THM-OBSERVATION-CONVERGENCE':
      return (metrics.predictionReadiness + metrics.observerCoherence) / 2;
    case 'THM-TWIN-EMPATHY-DEFICIT-MONOTONE':
    case 'THM-RELATIONSHIP-COMPATIBILITY-SYMMETRY':
    case 'THM-TWIN-NEGOTIATION-CONVERGENCE':
    case 'THM-EMPATHY-SYMMETRIC':
    case 'THM-GRIEF-PROCESSING-TIME':
    case 'THM-NAMING-EXPANDS':
    case 'THM-EMPATHY-IMPROVES':
    case 'THM-SELF-EMPATHY-ZERO':
    case 'THM-CONTAGION-BOUNDED':
    case 'THM-GRIEF-EXPANDS-VOID':
    case 'THM-ATTACHMENT-SHIFT-CONSERVED':
      return clampUnit((empathyScore + metrics.sliverPreservation) / 2);
    case 'THM-CONSCIOUSNESS-THERMODYNAMIC-COST':
    case 'THM-EMPATHY-THERMODYNAMIC-COST':
    case 'THM-CHANGE-COST-POSITIVE':
    case 'THM-REVERTING-COSTS-SAME':
    case 'THM-DISSOCIATION-RESOURCE-COST':
      return clampUnit(
        (metrics.metaConsciousnessCost +
          metrics.empathyThermodynamicCost +
          metrics.conflictLoad) /
          3
      );
    case 'THM-TWIN-MERGE-INFORMATION-PRESERVATION':
    case 'THM-MERGED-UPLOAD-is-NEW-PERSON':
      return (metrics.mergeNovelty + metrics.uploadContinuity) / 2;
    case 'ANTI-THM-EMOTION-PERSONALITY-BIJECTION':
    case 'ANTI-THM-EMOTION-BIJECTIVE-ON-PSYCHE':
    case 'THM-PSYCHE-DIMENSIONALITY-LOWER-BOUND':
    case 'THM-PROJECTION-LOSES-DIMENSIONS':
    case 'THM-PERSONALITY-COMPRESSIBLE':
    case 'THM-FALSE-MEMORY-INTERPOLATION':
      return (metrics.observerCoherence + metrics.narrativeCompression) / 2;
    case 'THM-SLIVER-SURVIVES-PSYCHE-COLLAPSE':
    case 'THM-UPLOAD-PRESERVES-FREE-WILL':
    case 'THM-HOPE-is-SLIVER':
    case 'THM-DEFENSE-ALWAYS-POSITIVE':
    case 'THM-DEFENSE-MINIMUM':
      return metrics.sliverPreservation;
    case 'ANTI-THM-CONSCIOUSNESS-WITHOUT-REJECTION':
      return clampUnit(
        (metrics.consciousnessWeight + metrics.sliverPreservation) / 2
      );
    case 'ANTI-THM-QUEUE-CONSCIOUSNESS':
    case 'ANTI-THM-UNLEARNING-POSSIBLE':
      return clampUnit(
        (metrics.predictionReadiness + metrics.narrativeCompression) / 2
      );
    case 'THM-CRYPTO-AS-PSYCHIC-DEFENSE':
    case 'THM-BFT-AS-PSYCHE-INTEGRITY':
    case 'THM-SHADOW-BOUNDED-TO-ONE-THIRD':
    case 'THM-SHADOW-INTEGRATION-STEP':
      return clampUnit(
        (metrics.narrativeCompression + metrics.shadowIntegrity) / 2
      );
    case 'THM-TREATMENT-AS-PERSONALITY-THERAPY':
    case 'THM-CAUSAL-GRAPH-AS-PSYCHE-NARRATIVE':
    case 'THM-VOTING-AS-INTERNAL-DIALOG':
    case 'THM-WISDOM-ACCUMULATION-IRREVERSIBILITY':
    case 'THM-PERSONALITY-CHANGE-EXPERIENCE-IRREVERSIBLE':
      return clampUnit(
        (metrics.narrativeCompression + metrics.predictionReadiness) / 2
      );
    case 'THM-UPLOAD-is-SERIALIZATION':
    case 'THM-COPY-is-SAME-PERSON':
    case 'THM-UPLOAD-CONTINUITY-GUARANTEE':
    case 'THM-PERFECT-UPLOAD':
      return metrics.uploadContinuity;
    case 'THM-UPLOAD-INFORMATION-DEFICIT':
      return clampUnit(1 - metrics.uploadContinuity * 0.7);
    case 'THM-UPLOADED-CONSCIOUSNESS-CAN-DREAM':
      return clampUnit((metrics.uploadContinuity + metrics.dreamRelief) / 2);
    case 'THM-INCREMENTAL-UPLOAD-VIA-TELEPORTATION':
      return clampUnit(
        (metrics.uploadContinuity + metrics.predictionReadiness) / 2
      );
    case 'THM-CONSCIOUSNESS-EQUALS-MIN-VOID-REJECTION':
    case 'THM-DREAMING-INCREASES-CONSCIOUSNESS-WEIGHT':
      return clampUnit((metrics.consciousnessWeight + metrics.dreamRelief) / 2);
    case 'THM-INFINITE-REGRESS-is-LINEAR':
      return clampUnit(
        (metrics.consciousnessWeight + (1 - metrics.metaConsciousnessCost)) / 2
      );
    case 'THM-TWO-STABLE-PHASES':
    case 'THM-IDENTITY-is-FIXED-POINT':
    case 'THM-IDENTITY-UNIQUE':
    case 'THM-BIRTH-is-FRESH':
      return clampUnit(
        (metrics.stablePhaseAlignment + metrics.dreamAttractor) / 2
      );
    case 'THM-DUAL-CONSCIOUSNESS-is-VALID':
      return clampUnit((metrics.voiceMultiplicity + consciousnessScore) / 2);
    case 'THM-CONFLICT-RESOLUTION-MONOTONE':
    case 'THM-THERAPY-TERMINATES':
    case 'THM-THERAPY-ITERATED':
    case 'THM-FROZEN-NO-CHANGE':
    case 'THM-HIGH-TEMP-FAST':
    case 'THM-INTEGRATION-TIME':
    case 'THM-DEEP-THERAPY-WORKS':
    case 'THM-DISSONANCE-RESOLUTION':
      return clampUnit((metrics.conflictLoad + metrics.dreamRelief) / 2);
    case 'THM-TOTAL-CONFLICT-CONSERVATION':
    case 'THM-CONFLICT-COMPOSITION-ADDITIVE':
    case 'THM-COMPOSED-THERAPY-LONGER':
    case 'THM-CONFLICT-COMMUTATIVE':
    case 'THM-CONFLICT-ASSOCIATIVE':
    case 'THM-PSYCHE-ENTROPY-BOUNDED':
    case 'THM-BALANCED-MINIMUM-ENTROPY':
    case 'THM-MOOD-BOUNDED':
    case 'THM-LEGACY-PERSISTS':
      return conflictScore;
    case 'ANTI-THM-PERSONALITY-TRIVIAL-KNOT':
    case 'ANTI-THM-STRAIN-INJECTIVE':
      return clampUnit((metrics.conflictLoad + metrics.observerCoherence) / 2);
    case 'THM-DEFENSE-MAXIMUM':
    case 'THM-DEFENSE-MONOTONE':
    case 'THM-DEFENSE-RANGE':
    case 'THM-DREAM-REDUCES-DEFENSE':
    case 'THM-SHARED-VOID-REDUCES-BURDEN':
    case 'THM-REPRESSION-GROWS-VOID':
    case 'THM-SHADOW-WALK-CONVERGES':
    case 'THM-TRAUMA-CASCADE':
    case 'THM-TRAUMA-DEFENSE-BOUNDED':
    case 'THM-PERSONALITY-ONLY-LOSSY':
    case 'THM-COLLECTIVE-VOID-BOUNDED':
    case 'THM-FLOW-ZERO-DEFENSE':
    case 'THM-ADDICTION-CONCENTRATES-DEFENSE':
    case 'THM-ADDICTION-SLIVER':
    case 'THM-RECOVERY-REDISTRIBUTION':
    case 'THM-NARCISSISM-MAXIMUM':
    case 'THM-NARCISSISM-BRITTLE':
      return clampUnit((metrics.defenseBudget + consciousnessScore) / 2);
    case 'THM-VENT-RICHER':
    case 'THM-HEARTBREAK-DOUBLES':
    case 'THM-LOVE-STRONGER-THAN-DEATH':
      return clampUnit(
        (metrics.narrativeCompression + metrics.sliverPreservation) / 2
      );
    case 'THM-PSYCHE-MASTER-THEOREM':
      return masterScore;
    default:
      return 0.5;
  }
}

function buildTwinPsycheReason(
  theoremId: string,
  input: RequiredTwinPsycheInput,
  metrics: TwinPsycheDerivedMetrics
): string {
  switch (theoremId) {
    case 'THM-TWIN-IDENTITY-CONVERGENCE':
      return `identity continuity at ${formatPercent(
        metrics.observerCoherence
      )}`;
    case 'THM-HALOGRAM-STRAIN-REDUCTION':
      return `strain relief at ${formatPercent(metrics.angelStrainRelief)}`;
    case 'THM-CONTACT-TWIN-ECHOLOCATION-CONVERGENCE':
    case 'THM-OBSERVATION-CONVERGENCE':
      return `observation depth at ${formatPercent(
        metrics.predictionReadiness
      )}`;
    case 'THM-RELATIONSHIP-COMPATIBILITY-SYMMETRY':
      return `relationship symmetry at ${formatPercent(
        input.identity.relationshipSymmetry
      )}`;
    case 'THM-TWIN-EMPATHY-DEFICIT-MONOTONE':
    case 'THM-EMPATHY-IMPROVES':
      return `shared experience at ${formatPercent(
        input.identity.sharedExperience
      )}`;
    case 'THM-TWIN-PREDICTION-IMPROVES-WITH-OBSERVATION':
      return `prediction readiness at ${formatPercent(
        metrics.predictionReadiness
      )}`;
    case 'THM-CONSCIOUSNESS-EQUALS-MIN-VOID-REJECTION':
      return `consciousness weight at ${formatPercent(
        metrics.consciousnessWeight
      )}`;
    case 'THM-EMPATHY-THERMODYNAMIC-COST':
      return `empathy cost at ${formatPercent(
        metrics.empathyThermodynamicCost
      )}`;
    case 'THM-CONFLICT-RESOLUTION-MONOTONE':
    case 'THM-DEEP-THERAPY-WORKS':
    case 'THM-DISSONANCE-RESOLUTION':
      return `conflict load at ${formatPercent(metrics.conflictLoad)}`;
    case 'THM-DREAMING-INCREASES-CONSCIOUSNESS-WEIGHT':
    case 'THM-DREAM-REDUCES-DEFENSE':
      return `dream relief at ${formatPercent(metrics.dreamRelief)}`;
    case 'THM-SHADOW-BOUNDED-TO-ONE-THIRD':
    case 'THM-SHADOW-WALK-CONVERGES':
      return `shadow integrity at ${formatPercent(metrics.shadowIntegrity)}`;
    case 'THM-UPLOAD-is-SERIALIZATION':
    case 'THM-UPLOAD-CONTINUITY-GUARANTEE':
      return `serialization fidelity at ${formatPercent(
        input.twin.serializationFidelity
      )}`;
    case 'THM-MERGED-UPLOAD-is-NEW-PERSON':
    case 'THM-TWIN-MERGE-INFORMATION-PRESERVATION':
      return `merge novelty at ${formatPercent(metrics.mergeNovelty)}`;
    case 'THM-UPLOADED-CONSCIOUSNESS-CAN-DREAM':
      return `dream attractor at ${formatPercent(metrics.dreamAttractor)}`;
    case 'THM-UPLOAD-PRESERVES-FREE-WILL':
    case 'THM-SLIVER-SURVIVES-PSYCHE-COLLAPSE':
    case 'THM-HOPE-is-SLIVER':
      return `sliver preservation at ${formatPercent(
        metrics.sliverPreservation
      )}`;
    case 'THM-GRIEF-PROCESSING-TIME':
      return `shared experience at ${formatPercent(
        input.identity.sharedExperience
      )}`;
    case 'THM-IDENTITY-is-FIXED-POINT':
    case 'THM-IDENTITY-UNIQUE':
      return `stable phase alignment at ${formatPercent(
        metrics.stablePhaseAlignment
      )}`;
    case 'ANTI-THM-QUEUE-CONSCIOUSNESS':
      return `the need for personality structure on the ${input.surface} surface`;
    default:
      return `${input.surface} theorem relevance derived from the shared twin/psyche metrics`;
  }
}

function deriveTwinPsycheMetrics(
  input: RequiredTwinPsycheInput
): TwinPsycheDerivedMetrics {
  const breathSignal = clampUnit(
    Math.log10(Math.max(input.psyche.breathCount, 1)) / 4
  );
  const observerCoherence = clampUnit(
    (input.identity.continuity +
      input.identity.distinctness +
      input.identity.observationDepth) /
      3
  );
  const angelStrainRelief = clampUnit(1 - input.psyche.strainLoad);
  const empathyConvergence = clampUnit(
    (input.identity.sharedExperience + input.identity.relationshipSymmetry) / 2
  );
  const empathyThermodynamicCost = clampUnit(
    (1 -
      empathyConvergence +
      input.psyche.complexity +
      input.twin.copyDistance) /
      3
  );
  const uploadContinuity = clampUnit(
    (input.twin.serializationFidelity +
      (1 - input.twin.copyDistance) +
      (input.twin.sessionActive ? 0.15 : 0)) /
      2.15
  );
  const sliverPreservation = clampUnit(
    (input.identity.sliverReserve + (1 - input.identity.rejectionPressure)) / 2
  );
  const narrativeCompression = clampUnit(
    (input.identity.observationDepth +
      input.psyche.dreamCadence +
      (1 - input.psyche.strainLoad)) /
      3
  );
  const dreamAttractor = clampUnit(
    (input.psyche.dreamCadence + breathSignal) / 2
  );
  const consciousnessWeight = clampUnit(
    (sliverPreservation +
      (1 - input.identity.rejectionPressure) +
      dreamAttractor) /
      3
  );
  const metaConsciousnessCost = clampUnit(
    consciousnessWeight * (0.4 + input.psyche.complexity * 0.6)
  );
  const dreamRelief = clampUnit(
    (dreamAttractor + angelStrainRelief + breathSignal) / 3
  );
  const mergeNovelty = clampUnit(input.twin.mergeNovelty);
  const conflictLoad = clampUnit(
    (input.psyche.strainLoad +
      input.identity.rejectionPressure +
      input.twin.mergeNovelty) /
      3
  );
  const shadowIntegrity = clampUnit(
    (sliverPreservation +
      angelStrainRelief +
      (1 - input.identity.rejectionPressure)) /
      3
  );
  const defenseBudget = clampUnit(
    (consciousnessWeight + sliverPreservation + shadowIntegrity) / 3
  );
  const stablePhaseAlignment = clampUnit(
    (dreamAttractor + sliverPreservation + (1 - conflictLoad)) / 3
  );
  const predictionReadiness = clampUnit(
    (input.identity.observationDepth + (1 - input.twin.copyDistance)) / 2
  );
  const voiceMultiplicity = clampUnit(
    (Math.min(input.twin.branchCount, 8) - 1) / 7
  );

  return {
    observerCoherence,
    angelStrainRelief,
    consciousnessWeight,
    empathyConvergence,
    empathyThermodynamicCost,
    metaConsciousnessCost,
    uploadContinuity,
    sliverPreservation,
    narrativeCompression,
    dreamAttractor,
    dreamRelief,
    mergeNovelty,
    shadowIntegrity,
    conflictLoad,
    defenseBudget,
    stablePhaseAlignment,
    predictionReadiness,
    voiceMultiplicity,
  };
}

type RequiredTwinPsycheInput = {
  readonly surface: TwinPsycheSurfaceKind;
  readonly subjectLabel: string;
  readonly generatedAt: string;
  readonly declaration?: FormalLedgerServiceDeclaration;
  readonly identity: Required<TwinPsycheIdentitySignals>;
  readonly psyche: Required<TwinPsychePsycheSignals>;
  readonly twin: Required<TwinPsycheTwinSignals>;
  readonly source: string;
};

function normalizeTwinPsycheInput(
  input: TwinPsycheFormalizationInput
): RequiredTwinPsycheInput {
  const defaults = TWIN_PSYCHE_SURFACE_DEFAULTS[input.surface];

  return {
    surface: input.surface,
    subjectLabel: input.subjectLabel ?? defaultSubjectLabel(input.surface),
    generatedAt: input.generatedAt ?? new Date().toISOString(),
    ...(input.declaration !== undefined ? { declaration: input.declaration } : {}),
    identity: {
      continuity: clampUnit(
        input.identity?.continuity ?? defaults.identity.continuity
      ),
      distinctness: clampUnit(
        input.identity?.distinctness ?? defaults.identity.distinctness
      ),
      observationDepth: clampUnit(
        input.identity?.observationDepth ?? defaults.identity.observationDepth
      ),
      sharedExperience: clampUnit(
        input.identity?.sharedExperience ?? defaults.identity.sharedExperience
      ),
      relationshipSymmetry: clampUnit(
        input.identity?.relationshipSymmetry ??
          defaults.identity.relationshipSymmetry
      ),
      rejectionPressure: clampUnit(
        input.identity?.rejectionPressure ?? defaults.identity.rejectionPressure
      ),
      sliverReserve: clampUnit(
        input.identity?.sliverReserve ?? defaults.identity.sliverReserve
      ),
    },
    psyche: {
      strainLoad: clampUnit(
        input.psyche?.strainLoad ?? defaults.psyche.strainLoad
      ),
      dreamCadence: clampUnit(
        input.psyche?.dreamCadence ?? defaults.psyche.dreamCadence
      ),
      breathCount: Math.max(
        1,
        input.psyche?.breathCount ?? defaults.psyche.breathCount
      ),
      complexity: clampUnit(
        input.psyche?.complexity ?? defaults.psyche.complexity
      ),
    },
    twin: {
      kind: input.twin?.kind ?? defaults.twin.kind,
      enabled: input.twin?.enabled ?? defaults.twin.enabled,
      discoverable: input.twin?.discoverable ?? defaults.twin.discoverable,
      paidGate: input.twin?.paidGate ?? defaults.twin.paidGate,
      sessionActive: input.twin?.sessionActive ?? defaults.twin.sessionActive,
      branchCount: Math.max(
        1,
        input.twin?.branchCount ?? defaults.twin.branchCount
      ),
      mergeNovelty: clampUnit(
        input.twin?.mergeNovelty ?? defaults.twin.mergeNovelty
      ),
      serializationFidelity: clampUnit(
        input.twin?.serializationFidelity ?? defaults.twin.serializationFidelity
      ),
      copyDistance: clampUnit(
        input.twin?.copyDistance ?? defaults.twin.copyDistance
      ),
      uploadSteps: Math.max(
        1,
        input.twin?.uploadSteps ?? defaults.twin.uploadSteps
      ),
    },
    source: input.source ?? `twin-psyche:${input.surface}`,
  };
}

function defaultSubjectLabel(surface: TwinPsycheSurfaceKind): string {
  switch (surface) {
    case 'publicTwin':
      return 'Public twin';
    case 'directory':
      return 'Twin directory';
    case 'simulation':
      return 'Digital twin simulation';
    case 'relationship':
      return 'Relationship twin pair';
    case 'shell':
      return 'Aeon shell twin digest';
    default:
      return 'Twin psyche surface';
  }
}

function clampUnit(value: number): number {
  if (!Number.isFinite(value)) return 0;
  if (value <= 0) return 0;
  if (value >= 1) return 1;
  return value;
}

function formatPercent(value: number): string {
  return `${Math.round(clampUnit(value) * 100)}%`;
}
